package com.cliplist.app

import android.util.Base64

/**
 * A real, decodable ~0.26s silent MP3 (generated with ffmpeg) for instrumented tests. Seeded files
 * must be genuine audio so MediaMetadataRetriever reads them as readable — otherwise, now that the
 * build excludes unreadable files, the tests would silently exercise the empty-playlist path.
 */
object TestAudio {
    fun mp3Bytes(): ByteArray = Base64.decode(MP3_BASE64, Base64.DEFAULT)

    private const val MP3_BASE64 =
        ""
}
